package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testSerializeSpecialFloatingPointValues_setsFlagTrue_andReturnsSelf() throws Exception {
    // Initially the field serializeSpecialFloatingPointValues should be default (false or as per DEFAULT_SPECIALIZE_FLOAT_VALUES)
    Field field = GsonBuilder.class.getDeclaredField("serializeSpecialFloatingPointValues");
    field.setAccessible(true);
    boolean before = field.getBoolean(gsonBuilder);

    // Call the focal method
    GsonBuilder returned = gsonBuilder.serializeSpecialFloatingPointValues();

    // The returned instance should be the same (this)
    assertSame(gsonBuilder, returned);

    // The field serializeSpecialFloatingPointValues should be true after the call
    boolean after = field.getBoolean(gsonBuilder);
    assertTrue(after);

    // If the default was already true, this still must be true (no change needed)
    // If default was false, it must change to true
    if (!before) {
      assertNotEquals(before, after);
    }
  }
}
